package com.hospital.management.controller.admission;import com.hospital.management.service.*;import com.hospital.management.service.impl.AdmissionServiceImpl;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admissions/status")public class AdmissionStatusServlet extends HttpServlet{private final AdmissionService service;public AdmissionStatusServlet(){this(new AdmissionServiceImpl());}public AdmissionStatusServlet(AdmissionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{r.sendError(405);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws IOException{Long id=AdmissionRequest.id(q.getParameter("admissionId"));if(id==null||!"cancel".equals(q.getParameter("action"))){r.sendError(400);return;}service.cancelAdmission(id,AdmissionRequest.audit(q),AdmissionRequest.user(q));r.sendRedirect(q.getContextPath()+"/admissions/view?id="+id);}}
